select *
from energy_report_daily_account
where report_date = #{reportDate}
  and account_id in

    #{accountId}

order by account_id asc

select account_id as accountId, max(owner_name) as accountName, max(electric_account_type) as electricAccountType, sum(coalesce(consume_power, 0)) as periodConsumePower, sum(coalesce(electric_charge_amount, 0)) as periodElectricChargeAmount, sum(coalesce(monthly_charge_amount, 0)) as periodMonthlyChargeAmount, sum(coalesce(recharge_amount, 0)) as periodRechargeAmount, sum(coalesce(correction_net_amount, 0)) as periodCorrectionAmount, sum(coalesce(total_debit_amount, 0)) as totalDebitAmount from energy_report_daily_account where report_date >= #{startDate} and report_date <= #{endDate}
and owner_name like concat('%', #{accountNameLike}, '%')
group by account_id order by accountName asc, accountId asc

select *
from energy_report_daily_account
where account_id = #{accountId}
  and report_date >= #{startDate}
  and report_date <= #{endDate}
order by report_date desc
limit 1
